import React, { useEffect, useState, useContext } from "react";
import axios from "axios";
import { AuthContext } from "../../context/AuthContext";

const API_BASE = "http://localhost:5000/api/notifications";

const AdminNotifications = () => {
  const { user } = useContext(AuthContext);
  const [notifications, setNotifications] = useState([]);

  // Lấy danh sách thông báo
  const fetchNotifications = async () => {
    try {
      const res = await axios.get(API_BASE, {
        headers: {
          Authorization: `Bearer ${user?.token}`,
        },
      });

      setNotifications(res.data.data || []);
    } catch (err) {
      console.error("❌ Lỗi lấy thông báo:", err);
    }
  };

  useEffect(() => {
    fetchNotifications();
  }, []);

  // Đánh dấu đã đọc 1 thông báo
  const markRead = async (id) => {
    try {
      await axios.put(
        `${API_BASE}/${id}/read`,
        {},
        {
          headers: { Authorization: `Bearer ${user?.token}` },
        }
      );
      fetchNotifications();
    } catch (err) {
      console.error("❌", err);
    }
  };

  // Đánh dấu tất cả đã đọc
  const markAll = async () => {
    try {
      await axios.put(
        `${API_BASE}/mark-all`,
        {},
        {
          headers: { Authorization: `Bearer ${user?.token}` },
        }
      );
      fetchNotifications();
    } catch (err) {
      console.error("❌", err);
    }
  };

  return (
    <div>
      <h2 className="text-xl font-semibold text-[#3e2f2f] mb-4">
        🔔 Thông báo
      </h2>

      <button
        onClick={markAll}
        className="mb-4 bg-pink-600 text-white px-4 py-2 rounded-md hover:bg-pink-700 transition"
      >
        Đánh dấu tất cả là đã đọc
      </button>

      {notifications.length === 0 ? (
        <p className="text-gray-500">Không có thông báo nào.</p>
      ) : (
        <div className="space-y-3">
          {notifications.map((n) => (
            <div
              key={n._id}
              className={`p-4 border rounded-lg shadow-sm ${
                n.read ? "bg-white" : "bg-pink-50 border-pink-200"
              }`}
            >
              <p className="font-medium text-[#4b2c35]">{n.message}</p>
              <p className="text-xs text-gray-500 mt-1">
                {new Date(n.createdAt).toLocaleString("vi-VN")}
              </p>

              {!n.read && (
                <button
                  onClick={() => markRead(n._id)}
                  className="mt-2 bg-gray-800 text-white px-3 py-1 rounded text-sm hover:bg-gray-900"
                >
                  Đánh dấu đã đọc
                </button>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default AdminNotifications;
